/**
 * @typedef {Object} User
 * @property {string} name - Der Vor- und Nachname
 * @property {number} age - Das Alter in Jahren
 * @property {boolean} isActive - Ob der Benutzer aktiv ist
 */

/** @type {User} */
const user = { name: "Max Mustermann", age: 30, isActive: true };

/** @type {User} */
const user2 = { name: "Beate Beispiel", age: 47, isActive: false };

/** @type {user} */
const user3 = { name: "Erich Exempel", age: 34, isActive: 12 };  // -> Warnmeldung wg. isActive
